rust.code:
impl Solution {
    pub fn min_partitions(n: String) -> i32 {
        n.as_bytes()
            .iter()
            .fold(0, |ans, &c| ans.max((c - b'0') as i32))
    }
}

c.code:
int minPartitions(char* n) {
    int ans = 0;
    for (int i = 0; n[i]; i++) {
        int v = n[i] - '0';
        if (v > ans) {
            ans = v;
        }
    }
    return ans;
}
